import React, { useState, useEffect } from 'react';
import { Bell, CheckCircle, TrendingUp, Users, MapPin, Loader2 } from 'lucide-react';

/**
 * SmartInsights - AI-powered insights component (lazy-loaded)
 * Shows intelligent recommendations and trends
 */
const SmartInsights = ({ leaveBalances, holidays, vacations }) => {
  const [aiInsights, setAiInsights] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Filter for future vacations only (for AI insights)
  const today = new Date();
  today.setHours(0, 0, 0, 0); // Start of today

  const futureVacations = vacations?.filter(vacation => {
    const startDate = new Date(vacation.fromDate || vacation.startDate);
    return startDate >= today;
  }) || [];

  // Only show destination insights if there are future vacations
  const showDestinationInsights = futureVacations.length > 0;

  // Debug logging (only once)
  const debugOnce = React.useRef(false);
  if (!debugOnce.current && futureVacations.length > 0) {
    console.log('SmartInsights Debug:', {
      totalVacations: vacations?.length || 0,
      futureVacations: futureVacations.length,
      firstFutureVacation: futureVacations[0],
      showDestinationInsights
    });
    debugOnce.current = true;
  }

  // Fetch AI insights for the first future vacation
  useEffect(() => {
    const fetchAIInsights = async () => {
      if (!futureVacations.length) return;

      const vacation = futureVacations[0];
      if (!vacation.destination || !vacation.fromDate || !vacation.toDate) return;

      setLoading(true);
      setError(null);

      try {
        // 5 second timeout to prevent getting stuck
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 5000);

        const token = localStorage.getItem('token');
        const response = await fetch('/api/vacation-insights', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
          },
          body: JSON.stringify({
            startDate: vacation.fromDate,
            endDate: vacation.toDate,
            destination: vacation.destination,
            vacationName: vacation.name
          }),
          signal: controller.signal
        });

        clearTimeout(timeoutId);

        if (response.ok) {
          const data = await response.json();
          setAiInsights(data);
        } else {
          setError('Failed to get AI insights');
        }
      } catch (err) {
        if (err.name === 'AbortError') {
          setError('Request timed out (5s)');
        } else {
          setError('AI service unavailable');
        }
        console.error('AI insights error:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchAIInsights();
  }, [futureVacations]);

  return (
    <div className="bg-white rounded-2xl p-6 shadow-lg">
      <div className="flex items-center mb-4">
        <Bell className="w-5 h-5 text-green-600 mr-2" />
        <h4 className="font-semibold text-gray-800">Smart Insights</h4>
      </div>

      <div className="space-y-3">
        {/* Long Weekend Alert - Emerald theme */}
        <div className="p-4 bg-gradient-to-r from-emerald-50 to-teal-50 rounded-xl shadow-sm hover:shadow-md transition-all duration-300 hover:scale-[1.02] border border-emerald-100">
          <div className="flex items-center justify-between mb-2">
            <h4 className="font-medium text-emerald-900">Long Weekend Detected!</h4>
            <div className="w-8 h-8 bg-emerald-200 rounded-full flex items-center justify-center">
              <CheckCircle className="w-5 h-5 text-emerald-600" />
            </div>
          </div>
          <p className="text-sm text-emerald-700">Mar 15-18 (4 days off)</p>
        </div>

        {/* Optimal Booking - Indigo theme */}
        <div className="p-4 bg-gradient-to-r from-indigo-50 to-blue-50 rounded-xl shadow-sm hover:shadow-md transition-all duration-300 hover:scale-[1.02] border border-indigo-100">
          <div className="flex items-center justify-between mb-2">
            <h4 className="font-medium text-indigo-900">Optimal Booking</h4>
            <div className="w-8 h-8 bg-indigo-200 rounded-full flex items-center justify-center">
              <TrendingUp className="w-5 h-5 text-indigo-600" />
            </div>
          </div>
          <p className="text-sm text-indigo-700">Book flights 2 weeks early</p>
        </div>

        {/* Team Sync - Violet theme */}
        <div className="p-4 bg-gradient-to-r from-violet-50 to-purple-50 rounded-xl shadow-sm hover:shadow-md transition-all duration-300 hover:scale-[1.02] border border-violet-100">
          <div className="flex items-center justify-between mb-2">
            <h4 className="font-medium text-violet-900">Team Sync</h4>
            <div className="w-8 h-8 bg-violet-200 rounded-full flex items-center justify-center">
              <Users className="w-5 h-5 text-violet-600" />
            </div>
          </div>
          <p className="text-sm text-violet-700">3 colleagues also planning leave</p>
        </div>

        {/* Destination Recommendation - Orange theme (Only for future vacations) */}
        {showDestinationInsights && (
          <div className="p-4 bg-gradient-to-r from-orange-50 to-amber-50 rounded-xl shadow-sm hover:shadow-md transition-all duration-300 hover:scale-[1.02] border border-orange-100">
            <div className="flex items-center justify-between mb-2">
              <h4 className="font-medium text-orange-900">Perfect Destination</h4>
              <div className="w-8 h-8 bg-orange-200 rounded-full flex items-center justify-center">
                <MapPin className="w-5 h-5 text-orange-600" />
              </div>
            </div>
            <p className="text-sm text-orange-700">
              {loading ? (
                <span className="flex items-center">
                  <Loader2 className="w-3 h-3 mr-1 animate-spin" />
                  Getting AI insights...
                </span>
              ) : error ? (
                <span className="text-red-600">{error}</span>
              ) : aiInsights?.ai_analysis?.ai_insights?.smart_suggestion ? (
                aiInsights.ai_analysis.ai_insights.smart_suggestion
              ) : futureVacations[0]?.destination ? (
                `${futureVacations[0].destination} - Getting recommendations...`
              ) : (
                'Plan your next destination for smart recommendations'
              )}
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default SmartInsights;
